module.render:
    const color = args.color || 'var(--accent-color)';
    const activeArr = Array.isArray(args.active) ? args.active.map(Number) : [];
    let html = `\n\n<div class="mdp-mod-process" style="--proc-color: ${color};">\n`;
    sections.forEach((section, index) => {
      const contentStr = section.trim();
      if (!contentStr) return;
      const currentNum = index + 1;
      const isActive = activeArr.length === 0 || activeArr.includes(currentNum);
      const stepBg = isActive ? 'var(--proc-color)' : '#e2e8f0';
      const stepText = isActive ? 'white' : '#718096';
      html += `
<div class="mdp-process-step" style="--step-bg: ${stepBg}; --step-text: ${stepText};">
<div class="mdp-process-content">

${contentStr}

</div>
</div>
      `;
    });

    html += `</div>\n\n`;
    return html;
